// Calculate the previous 7-day billing window
const now = new Date();

const endDate = new Date(now);
endDate.setUTCHours(0, 0, 0, 0);

const startDate = new Date(endDate);
startDate.setUTCDate(startDate.getUTCDate() - 7);

const fmt = d => d.toISOString().split('T')[0];

return [{
  json: {
    reportWindow: {
      start: fmt(startDate),
      end:   fmt(endDate),
      label: `${fmt(startDate)} to ${fmt(endDate)}`
    }
  }
}];

const response = $input.first().json;

// ── SAMPLE / FALLBACK DATA ────────────────────────────────────────────
// Used when Cost Explorer is not connected (local testing mode).
// Replace with real API response parsing once credentials are configured.
const sampleData = {
  totalUsd: 847.32,
  currency: 'USD',
  period: $('Set Report Window').first().json.reportWindow.label,
  topServices: [
    { service: 'Amazon EC2',           cost: 412.80 },
    { service: 'Amazon RDS',           cost: 198.50 },
    { service: 'Amazon S3',            cost: 87.40  },
    { service: 'AWS Lambda',           cost: 54.22  },
    { service: 'Amazon CloudFront',    cost: 34.18  },
    { service: 'Amazon Route 53',      cost: 28.50  },
    { service: 'Amazon CloudWatch',    cost: 17.90  },
    { service: 'AWS Data Transfer',    cost: 13.82  }
  ],
  vsLastWeek: { delta: +62.14, pct: '+7.9%' },
  unusedResources: [
    'ec2: 3 stopped instances (t3.medium) in us-east-1 — idle 14+ days',
    's3: 2 buckets with no access in 90 days',
    'rds: 1 snapshot older than 30 days'
  ]
};

// If real API data is present, parse it here:
let costData = sampleData;
if (response && response.ResultsByTime && response.ResultsByTime.length > 0) {
  const groups = response.ResultsByTime[0].Groups || [];
  let total = 0;
  const services = groups.map(g => {
    const cost = parseFloat(g.Metrics.UnblendedCost.Amount);
    total += cost;
    return { service: g.Keys[0], cost: parseFloat(cost.toFixed(2)) };
  }).sort((a, b) => b.cost - a.cost);

  costData = {
    totalUsd: parseFloat(total.toFixed(2)),
    currency: 'USD',
    period: $('Set Report Window').first().json.reportWindow.label,
    topServices: services.slice(0, 8),
    vsLastWeek: { delta: null, pct: 'N/A — prior week comparison requires additional API call' },
    unusedResources: []
  };
}

return [{ json: { costData } }];

const response = $input.first().json;

// Extract the text content from Anthropic messages API response
let narrative = '';
if (response.content && Array.isArray(response.content)) {
  narrative = response.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('\n');
} else if (typeof response.content === 'string') {
  narrative = response.content;
} else {
  narrative = JSON.stringify(response);
}

const costData = $('Parse and Compact Cost Data').first().json.costData;

return [{
  json: {
    narrative,
    summary: {
      total:   `$${costData.totalUsd}`,
      period:  costData.period,
      currency: costData.currency
    }
  }
}];

const response = $input.first().json;

let recommendations = '';
try {
  recommendations = response.candidates[0].content.parts[0].text || 'No recommendations returned.';
} catch (e) {
  recommendations = 'Gemini recommendations unavailable: ' + e.message;
}

return [{ json: { recommendations } }];

